// FIELD-OWNERSHIP TABLE — every metadata key: exactly one group, one applier, one manager.
//  ManagerDesired    → gc.spec.*   : session_name, session_name_explicit, alias, session_origin, rig,
//                       pool_slot, desired_config_hash, wake_mode, prompt_ref, transport, deleted, finalizers
//  ManagerReconciler → gc.status.* : state, sleep_reason, started_config_hash, live_hash, instance_token,
//                       generation, last_woke_at, synced_at, priming_{attempted,confirmed},
//                       pending_create_{claim,started_at,rollback}, drain_*, session_circuit_*,
//                       suspended_at, reset_committed_at, quarantined_until
//  ManagerExternal   → gc.ext.*    : operator annotations — never read by Plan

type SessionSpec struct { Name, Alias, Rig, DesiredConfigHash, PromptRef, Transport string; PoolSlot int; WakeMode WakeMode; Deleted bool; Finalizers []Finalizer }
type SessionStatus struct { State LifecycleState; StartedHash, LiveHash, InstanceToken string; Generation int64; Priming, Reset IntentMarker; Circuit CircuitState; Sleep SleepReason; QuarantinedUntil time.Time }

func (s *Store) ApplySpec(ctx context.Context, id BeadID, spec SessionSpec) (Rev, error)                 // whole-value; SOLE writer of gc.spec.*; diffs before writing (Dolt churn)
func (s *Store) ApplyStatus(ctx context.Context, id BeadID, st SessionStatus, expect Rev) (Rev, error)   // whole-value; SOLE writer of gc.status.*; CAS on Rev

type ProbeResult int  // Observed | Unobserved{Err}
type Liveness int     // Alive | Dead | Unknown   (Unknown iff Unobserved — errors are never collapsed to false)
type RuntimeFacts struct { Probe ProbeResult; Live Liveness; Attached bool; IdentityMatch TriBool; LastActive time.Time }
type Observation struct { Key SessionKey; Spec *SessionSpec /*nil=durable-absent*/; Status *SessionStatus; Rev Rev; Runtime RuntimeFacts; Desired *DesiredEntry /*config snapshot*/; Now time.Time }

func Observe(ctx context.Context, d ObserveDeps, key SessionKey) (Observation, error)  // exactly ONE worker.ObserveHandle probe, under a per-probe context deadline

func Plan(obs Observation) Actions  // pure, clock-free, exhaustive over LifecycleState incl. StateUnrecognized; re-run after Execute ⇒ ∅

type Actions []Action // closed sum:
//  ActionStart{Budgeted}, ActionPrime{IntentMarker}, ActionHealStatus, ActionAdopt{spec SessionSpec},
//  ActionTeardown{W LiveTargetWitness}, ActionRemoveFinalizer{C DeathCertificate},
//  ActionClose{P CloseProof}, ActionQuarantine{Until time.Time}, ActionRequeueAfter{time.Duration}

type Queue[K comparable] interface { Add(K); AddRateLimited(K); AddAfter(K, time.Duration); Forget(K); Get() (K, bool); Done(K) }
// N small workers; Get never yields a key already in flight (per-key exclusivity = single-writer-per-session preserved).
// Per-key exponential backoff WITH jitter; global token bucket on ActionStart; Forget on converge.
// 30s ticker = resync floor: enqueues ALL keys (level-triggered safety net). bead.updated / fsnotify / pokes = hints that enqueue keys.
// Backpressure in one process: dedup bounds the queue at #sessions; probes carry deadlines; starts are token-bucketed.

const FinalizerRuntimeTeardown Finalizer = "runtime-teardown"  // stamped unconditionally by ApplySpec at creation — cannot be forgotten, there is one applier
// Deletion is durable intent, never an event: ApplySpec(spec{Deleted: true}).
// Plan: Deleted ∧ Finalizers≠∅ ⇒ ActionTeardown{LiveTargetWitness} … next pass, Probe==Observed ∧ Live==Dead ⇒ ActionRemoveFinalizer{DeathCertificate}.
func (s *Store) Close(ctx context.Context, id BeadID, p CloseProof) error  // the ONLY close API; CloseProof mintable solely from a decoded Status whose finalizer set is empty

type IntentMarker struct { AttemptedAt, ConfirmedAt time.Time; Attempts int }
func (m IntentMarker) Eligible(now time.Time, b Backoff) bool  // bounded retry
// Protocol: ApplyStatus(attempted) → side effect → ApplyStatus(confirmed). Crash anywhere ⇒ at most one duplicate per backoff window.

